3361 Instruction *InstCombinerImpl::foldICmpSelectConstant(ICmpInst &Cmp,
3362                                                       SelectInst *Select,
3363                                                       ConstantInt *C) {
3364 
3365   assert(C && "Cmp RHS should be a constant int!");
3366   // If we're testing a constant value against the result of a three way
3367   // comparison, the result can be expressed directly in terms of the
3368   // original values being compared.  Note: We could possibly be more
3369   // aggressive here and remove the hasOneUse test. The original select is
3370   // really likely to simplify or sink when we remove a test of the result.
3371   Value *OrigLHS, *OrigRHS;
3372   ConstantInt *C1LessThan, *C2Equal, *C3GreaterThan;
3373   if (Cmp.hasOneUse() &&
3374       matchThreeWayIntCompare(Select, OrigLHS, OrigRHS, C1LessThan, C2Equal,
3375                               C3GreaterThan)) {
3376     assert(C1LessThan && C2Equal && C3GreaterThan);
3377 
3378     bool TrueWhenLessThan = ICmpInst::compare(
3379         C1LessThan->getValue(), C->getValue(), Cmp.getPredicate());
3380     bool TrueWhenEqual = ICmpInst::compare(C2Equal->getValue(), C->getValue(),
3381                                            Cmp.getPredicate());
3382     bool TrueWhenGreaterThan = ICmpInst::compare(
3383         C3GreaterThan->getValue(), C->getValue(), Cmp.getPredicate());
3384 
3385     // This generates the new instruction that will replace the original Cmp
3386     // Instruction. Instead of enumerating the various combinations when
3387     // TrueWhenLessThan, TrueWhenEqual and TrueWhenGreaterThan are true versus
3388     // false, we rely on chaining of ORs and future passes of InstCombine to
3389     // simplify the OR further (i.e. a s< b || a == b becomes a s<= b).
3390 
3391     // When none of the three constants satisfy the predicate for the RHS (C),
3392     // the entire original Cmp can be simplified to a false.
3393     Value *Cond = Builder.getFalse();
3394     if (TrueWhenLessThan)
3395       Cond = Builder.CreateOr(
3396           Cond, Builder.CreateICmp(ICmpInst::ICMP_SLT, OrigLHS, OrigRHS));
3397     if (TrueWhenEqual)
3398       Cond = Builder.CreateOr(
3399           Cond, Builder.CreateICmp(ICmpInst::ICMP_EQ, OrigLHS, OrigRHS));
3400     if (TrueWhenGreaterThan)
3401       Cond = Builder.CreateOr(
3402           Cond, Builder.CreateICmp(ICmpInst::ICMP_SGT, OrigLHS, OrigRHS));
3403 
3404     return replaceInstUsesWith(Cmp, Cond);
3405   }
