3765 static Instruction *foldCtpopPow2Test(ICmpInst &I, IntrinsicInst *CtpopLhs,
3766                                       const APInt &CRhs,
3767                                       InstCombiner::BuilderTy &Builder,
3768                                       const SimplifyQuery &Q) {
3769   assert(CtpopLhs->getIntrinsicID() == Intrinsic::ctpop &&
3770          "Non-ctpop intrin in ctpop fold");
3771   if (!CtpopLhs->hasOneUse())
3772     return nullptr;
3773 
3774   // Power of 2 test:
3775   //    isPow2OrZero : ctpop(X) u< 2
3776   //    isPow2       : ctpop(X) == 1
3777   //    NotPow2OrZero: ctpop(X) u> 1
3778   //    NotPow2      : ctpop(X) != 1
3779   // If we know any bit of X can be folded to:
3780   //    IsPow2       : X & (~Bit) == 0
3781   //    NotPow2      : X & (~Bit) != 0
3782   const ICmpInst::Predicate Pred = I.getPredicate();
3783   if (((I.isEquality() || Pred == ICmpInst::ICMP_UGT) && CRhs == 1) ||
3784       (Pred == ICmpInst::ICMP_ULT && CRhs == 2)) {
3785     Value *Op = CtpopLhs->getArgOperand(0);
3786     KnownBits OpKnown = computeKnownBits(Op, Q.DL, Q.AC, Q.CxtI, Q.DT);
3787     // No need to check for count > 1, that should be already constant folded.
3788     if (OpKnown.countMinPopulation() == 1) {
3789       Value *And = Builder.CreateAnd(
3790           Op, Constant::getIntegerValue(Op->getType(), ~(OpKnown.One)));
3791       return new ICmpInst(
3792           (Pred == ICmpInst::ICMP_EQ || Pred == ICmpInst::ICMP_ULT)
3793               ? ICmpInst::ICMP_EQ
3794               : ICmpInst::ICMP_NE,
3795           And, Constant::getNullValue(Op->getType()));
3796     }
3797   }
3798 
3799   return nullptr;
3800 }
