4055 static Instruction *
4056 foldICmpUSubSatOrUAddSatWithConstant(CmpPredicate Pred, SaturatingInst *II,
4057                                      const APInt &C,
4058                                      InstCombiner::BuilderTy &Builder) {
4059   // This transform may end up producing more than one instruction for the
4060   // intrinsic, so limit it to one user of the intrinsic.
4061   if (!II->hasOneUse())
4062     return nullptr;
4063 
4064   // Let Y        = [add/sub]_sat(X, C) pred C2
4065   //     SatVal   = The saturating value for the operation
4066   //     WillWrap = Whether or not the operation will underflow / overflow
4067   // => Y = (WillWrap ? SatVal : (X binop C)) pred C2
4068   // => Y = WillWrap ? (SatVal pred C2) : ((X binop C) pred C2)
4069   //
4070   // When (SatVal pred C2) is true, then
4071   //    Y = WillWrap ? true : ((X binop C) pred C2)
4072   // => Y = WillWrap || ((X binop C) pred C2)
4073   // else
4074   //    Y =  WillWrap ? false : ((X binop C) pred C2)
4075   // => Y = !WillWrap ?  ((X binop C) pred C2) : false
4076   // => Y = !WillWrap && ((X binop C) pred C2)
4077   Value *Op0 = II->getOperand(0);
4078   Value *Op1 = II->getOperand(1);
4079 
4080   const APInt *COp1;
4081   // This transform only works when the intrinsic has an integral constant or
4082   // splat vector as the second operand.
4083   if (!match(Op1, m_APInt(COp1)))
4084     return nullptr;
4085 
4086   APInt SatVal;
4087   switch (II->getIntrinsicID()) {
4088   default:
4089     llvm_unreachable(
4090         "This function only works with usub_sat and uadd_sat for now!");
4091   case Intrinsic::uadd_sat:
4092     SatVal = APInt::getAllOnes(C.getBitWidth());
4093     break;
4094   case Intrinsic::usub_sat:
4095     SatVal = APInt::getZero(C.getBitWidth());
4096     break;
4097   }
4098 
4099   // Check (SatVal pred C2)
4100   bool SatValCheck = ICmpInst::compare(SatVal, C, Pred);
4101 
4102   // !WillWrap.
4103   ConstantRange C1 = ConstantRange::makeExactNoWrapRegion(
4104       II->getBinaryOp(), *COp1, II->getNoWrapKind());
4105 
4106   // WillWrap.
4107   if (SatValCheck)
4108     C1 = C1.inverse();
4109 
4110   ConstantRange C2 = ConstantRange::makeExactICmpRegion(Pred, C);
4111   if (II->getBinaryOp() == Instruction::Add)
4112     C2 = C2.sub(*COp1);
4113   else
4114     C2 = C2.add(*COp1);
4115 
4116   Instruction::BinaryOps CombiningOp =
4117       SatValCheck ? Instruction::BinaryOps::Or : Instruction::BinaryOps::And;
4118 
4119   std::optional<ConstantRange> Combination;
4120   if (CombiningOp == Instruction::BinaryOps::Or)
4121     Combination = C1.exactUnionWith(C2);
4122   else /* CombiningOp == Instruction::BinaryOps::And */
4123     Combination = C1.exactIntersectWith(C2);
4124 
4125   if (!Combination)
4126     return nullptr;
4127 
4128   CmpInst::Predicate EquivPred;
4129   APInt EquivInt;
4130   APInt EquivOffset;
4131 
4132   Combination->getEquivalentICmp(EquivPred, EquivInt, EquivOffset);
4133 
4134   return new ICmpInst(
4135       EquivPred,
4136       Builder.CreateAdd(Op0, ConstantInt::get(Op1->getType(), EquivOffset)),
4137       ConstantInt::get(Op1->getType(), EquivInt));
4138 }
