4196 /// Fold an icmp with LLVM intrinsic and constant operand: icmp Pred II, C.
4197 Instruction *InstCombinerImpl::foldICmpIntrinsicWithConstant(ICmpInst &Cmp,
4198                                                              IntrinsicInst *II,
4199                                                              const APInt &C) {
4200   ICmpInst::Predicate Pred = Cmp.getPredicate();
4201 
4202   // Handle folds that apply for any kind of icmp.
4203   switch (II->getIntrinsicID()) {
4204   default:
4205     break;
4206   case Intrinsic::uadd_sat:
4207   case Intrinsic::usub_sat:
4208     if (auto *Folded = foldICmpUSubSatOrUAddSatWithConstant(
4209             Pred, cast<SaturatingInst>(II), C, Builder))
4210       return Folded;
4211     break;
4212   case Intrinsic::ctpop: {
4213     const SimplifyQuery Q = SQ.getWithInstruction(&Cmp);
4214     if (Instruction *R = foldCtpopPow2Test(Cmp, II, C, Builder, Q))
4215       return R;
4216   } break;
4217   case Intrinsic::scmp:
4218   case Intrinsic::ucmp:
4219     if (auto *Folded = foldICmpOfCmpIntrinsicWithConstant(Pred, II, C, Builder))
4220       return Folded;
4221     break;
4222   }
4223 
4224   if (Cmp.isEquality())
4225     return foldICmpEqIntrinsicWithConstant(Cmp, II, C);
4226 
4227   Type *Ty = II->getType();
4228   unsigned BitWidth = C.getBitWidth();
4229   switch (II->getIntrinsicID()) {
4230   case Intrinsic::ctpop: {
4231     // (ctpop X > BitWidth - 1) --> X == -1
4232     Value *X = II->getArgOperand(0);
4233     if (C == BitWidth - 1 && Pred == ICmpInst::ICMP_UGT)
4234       return CmpInst::Create(Instruction::ICmp, ICmpInst::ICMP_EQ, X,
4235                              ConstantInt::getAllOnesValue(Ty));
4236     // (ctpop X < BitWidth) --> X != -1
4237     if (C == BitWidth && Pred == ICmpInst::ICMP_ULT)
4238       return CmpInst::Create(Instruction::ICmp, ICmpInst::ICMP_NE, X,
4239                              ConstantInt::getAllOnesValue(Ty));
4240     break;
4241   }
4242   case Intrinsic::ctlz: {
4243     // ctlz(0bXXXXXXXX) > 3 -> 0bXXXXXXXX < 0b00010000
4244     if (Pred == ICmpInst::ICMP_UGT && C.ult(BitWidth)) {
4245       unsigned Num = C.getLimitedValue();
4246       APInt Limit = APInt::getOneBitSet(BitWidth, BitWidth - Num - 1);
4247       return CmpInst::Create(Instruction::ICmp, ICmpInst::ICMP_ULT,
4248                              II->getArgOperand(0), ConstantInt::get(Ty, Limit));
4249     }
