3089 /// Try to match V as a boolean-controlled value: either
3090 ///   select i1 Cond, C_true, C_false
3091 ///   zext i1 Cond  (equivalent to select i1 Cond, 1, 0)
3092 ///   sext i1 Cond  (equivalent to select i1 Cond, -1, 0)
3093 static bool matchBooleanMap(Value *V, Value *&Cond, Constant *&TrueC,
3094                             Constant *&FalseC) {
3095   if (match(V, m_Select(m_Value(Cond), m_Constant(TrueC), m_Constant(FalseC))))
3096     return true;
3097 
3098   Type *Ty = V->getType();
3099   if (match(V, m_ZExt(m_Value(Cond))) &&
3100       Cond->getType()->isIntOrIntVectorTy(1)) {
3101     TrueC = ConstantInt::get(Ty, 1);
3102     FalseC = ConstantInt::get(Ty, 0);
3103     return true;
3104   }
3105   if (match(V, m_SExt(m_Value(Cond))) &&
3106       Cond->getType()->isIntOrIntVectorTy(1)) {
3107     FalseC = ConstantInt::get(Ty, 0);
3108     TrueC = Constant::getAllOnesValue(Ty);
3109     return true;
3110   }
3111   return false;
3112 }
