3180   if (Add->hasNoUnsignedWrap() &&
3181       (Pred == ICmpInst::ICMP_UGT || Pred == ICmpInst::ICMP_ULT)) {
3182     bool Overflow;
3183     APInt NewC = C.usub_ov(*C2, Overflow);
3184     // If there is overflow, the result must be true or false.
3185     if (!Overflow)
3186       // icmp Pred (add nsw X, C2), C --> icmp Pred X, (C - C2)
3187       return new ICmpInst(Pred, X, ConstantInt::get(Ty, NewC));
3188   }
3189 
3190   CmpInst::Predicate ChosenPred = Pred.getPreferredSignedPredicate();
3191 
3192   if (Add->hasNoSignedWrap() &&
3193       (ChosenPred == ICmpInst::ICMP_SGT || ChosenPred == ICmpInst::ICMP_SLT)) {
3194     bool Overflow;
3195     APInt NewC = C.ssub_ov(*C2, Overflow);
3196     if (!Overflow)
3197       // icmp samesign ugt/ult (add nsw X, C2), C
3198       //   -> icmp sgt/slt X, (C - C2)
3199       return new ICmpInst(ChosenPred, X, ConstantInt::get(Ty, NewC));
3200   }
