3208   auto CR = ConstantRange::makeExactICmpRegion(Pred, C).subtract(*C2);
3209   const APInt &Upper = CR.getUpper();
3210   const APInt &Lower = CR.getLower();
3211   if (Cmp.isSigned()) {
3212     if (Lower.isSignMask())
3213       return new ICmpInst(ICmpInst::ICMP_SLT, X, ConstantInt::get(Ty, Upper));
3214     if (Upper.isSignMask())
3215       return new ICmpInst(ICmpInst::ICMP_SGE, X, ConstantInt::get(Ty, Lower));
3216   } else {
3217     if (Lower.isMinValue())
3218       return new ICmpInst(ICmpInst::ICMP_ULT, X, ConstantInt::get(Ty, Upper));
3219     if (Upper.isMinValue())
3220       return new ICmpInst(ICmpInst::ICMP_UGE, X, ConstantInt::get(Ty, Lower));
3221   }
3222 
3223   // This set of folds is intentionally placed after folds that use no-wrapping
3224   // flags because those folds are likely better for later analysis/codegen.
3225   const APInt SMax = APInt::getSignedMaxValue(Ty->getScalarSizeInBits());
3226   const APInt SMin = APInt::getSignedMinValue(Ty->getScalarSizeInBits());
3227 
3228   // Fold compare with offset to opposite sign compare if it eliminates offset:
3229   // (X + C2) >u C --> X <s -C2 (if C == C2 + SMAX)
3230   if (Pred == CmpInst::ICMP_UGT && C == *C2 + SMax)
