3232 
3233   // (X + C2) <u C --> X >s ~C2 (if C == C2 + SMIN)
3234   if (Pred == CmpInst::ICMP_ULT && C == *C2 + SMin)
3235     return new ICmpInst(ICmpInst::ICMP_SGT, X, ConstantInt::get(Ty, ~(*C2)));
3236 
3237   // (X + C2) >s C --> X <u (SMAX - C) (if C == C2 - 1)
3238   if (Pred == CmpInst::ICMP_SGT && C == *C2 - 1)
3239     return new ICmpInst(ICmpInst::ICMP_ULT, X, ConstantInt::get(Ty, SMax - C));
3240 
3241   // (X + C2) <s C --> X >u (C ^ SMAX) (if C == C2)
3242   if (Pred == CmpInst::ICMP_SLT && C == *C2)
3243     return new ICmpInst(ICmpInst::ICMP_UGT, X, ConstantInt::get(Ty, C ^ SMax));
3244 
3245   // (X + -1) <u C --> X <=u C (if X is never null)
3246   if (Pred == CmpInst::ICMP_ULT && C2->isAllOnes()) {
